package com.vidaysalud.veterinaria.consultaservicio.model;import jakarta.persistence.*;import lombok.*;import java.math.BigDecimal;import java.time.LocalDateTime;@Entity @Table(name="consulta",uniqueConstraints=@UniqueConstraint(name="uq_consulta_cita",columnNames="id_cita")) @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder public class Consulta{@Id @GeneratedValue(strategy=GenerationType.IDENTITY) @Column(name="id_consulta")private Integer idConsulta;@Column(name="id_mascota",nullable=false)private Integer idMascota;@Column(name="id_veterinario",nullable=false)private Integer idVeterinario;@Column(name="id_cita",unique=true)private Integer idCita;@Column(name="fecha_consulta",nullable=false)private LocalDateTime fechaConsulta;@Lob private String motivo;@Lob private String diagnostico;@Lob private String observaciones;@Column(name="peso_actual",precision=5,scale=2)private BigDecimal pesoActual;@Column(precision=4,scale=2)private BigDecimal temperatura;@Column(name="costo_consulta",nullable=false,precision=10,scale=2)private BigDecimal costoConsulta;}